fn lookup_in(tbl: &'static [(&'static str, f64)], text: &str) -> Option<f64> {
    let mut lo = 0usize;
    let mut hi = tbl.len();
    while lo < hi {
        let mid = (lo + hi) / 2;
        let (k, v) = tbl[mid];
        match k.cmp(text) {
            std::cmp::Ordering::Equal => return Some(v),
            std::cmp::Ordering::Less => lo = mid + 1,
            std::cmp::Ordering::Greater => hi = mid,
        }
    }
    None
}
